import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"20. Casual Employment","description":"","frontmatter":{"title":"20. Casual Employment","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime","employment","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/employment/20-casual-employment.md","filePath":"ebas/biomedical-engineers/employment/20-casual-employment.md"}'),l={name:"ebas/biomedical-engineers/employment/20-casual-employment.md"};function s(r,e,i,p,m,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_20-casual-employment" tabindex="-1">20. Casual Employment <a class="header-anchor" href="#_20-casual-employment" aria-label="Permalink to &quot;20. Casual Employment&quot;">​</a></h1><p><strong>20.1</strong> An Employee is a casual Employee if they meet the definition of a casual Employee under section 15A of the Act.</p><p><strong>20.2</strong> Subject to the minimum engagement period, a casual Employee’s employment may be terminated without prior notice by either the Employer or the Employee.</p><p><strong>20.3</strong> The minimum engagement period for a casual employee is 3 hours.</p><p><strong>20.4</strong> Payments A casual Employee will be paid for all work, other than for overtime (see subclause 46.3(b)), performed on a:</p><p><strong>(a)</strong> weekday - an amount equal to one thirty eighth (1/38th) of the weekly wage appropriate to the Employee&#39;s classification per hour plus 25%;</p><p><strong>(b)</strong> Saturday or Sunday - an amount equal to one thirty eighth (1/38th) of the weekly wage appropriate to the Employee&#39;s classification plus 75%; and</p><p><strong>(c)</strong> Public holiday - an amount equal to one thirty eighth (1/38th) of the weekly wage appropriate to the Employee&#39;s classification plus 75%.</p><p><strong>20.5</strong> Overtime also applies to casual employees.</p><p><strong>20.6</strong> The hourly rate a casual staff member receives shall include a component paid in lieu of leave and public holiday entitlements.</p><p><strong>20.7</strong> Casual Employees are entitled to Long Service Leave in accordance with the Long Service Leave Act 2018 (Vic) (or applicable legislation).</p><p>Plain language terms: casual.</p>',12)])])}const y=a(l,[["render",s]]);export{h as __pageData,y as default};
